import{_ as s,o as n,c as e,a2 as t}from"./chunks/framework.CBOyQ9KN.js";const u=JSON.parse('{"title":"Cursor MCP 协议实现分析 (cursor-mcp)","description":"","frontmatter":{},"headers":[],"relativePath":"04-mcp-protocol/cursor-mcp-analysis.md","filePath":"04-mcp-protocol/cursor-mcp-analysis.md","lastUpdated":null}'),r={name:"04-mcp-protocol/cursor-mcp-analysis.md"};function o(l,a,p,i,c,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="cursor-mcp-协议实现分析-cursor-mcp" tabindex="-1">Cursor MCP 协议实现分析 (cursor-mcp) <a class="header-anchor" href="#cursor-mcp-协议实现分析-cursor-mcp" aria-label="Permalink to &quot;Cursor MCP 协议实现分析 (cursor-mcp)&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>cursor-mcp 扩展实现了 <strong>Model Context Protocol (MCP)</strong> 支持，这是 Anthropic 提出的 AI 工具集成标准协议。Cursor 使用 MCP 作为 Agent 与外部工具/服务交互的标准接口。</p><h2 id="扩展元数据" tabindex="-1">扩展元数据 <a class="header-anchor" href="#扩展元数据" aria-label="Permalink to &quot;扩展元数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>名称</td><td>cursor-mcp</td></tr><tr><td>发布者</td><td>anysphere</td></tr><tr><td>版本</td><td>0.0.1</td></tr><tr><td>入口</td><td>./dist/main (2.8MB)</td></tr><tr><td>激活事件</td><td>onStartupFinished, onUri</td></tr><tr><td>运行类型</td><td>workspace</td></tr><tr><td>API提案</td><td>control, cursor, cursorTracing</td></tr></tbody></table><h2 id="mcp-sdk-版本" tabindex="-1">MCP SDK 版本 <a class="header-anchor" href="#mcp-sdk-版本" aria-label="Permalink to &quot;MCP SDK 版本&quot;">​</a></h2><ul><li><strong>@modelcontextprotocol/sdk</strong>: v1.25.1</li><li><strong>官方源</strong>: Anthropic, PBC (<a href="https://anthropic.com" target="_blank" rel="noreferrer">https://anthropic.com</a>)</li><li><strong>文档</strong>: <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">https://modelcontextprotocol.io</a></li><li><strong>SDK 仓库</strong>: <a href="https://github.com/modelcontextprotocol/typescript-sdk" target="_blank" rel="noreferrer">https://github.com/modelcontextprotocol/typescript-sdk</a></li><li><strong>Cursor 补丁</strong>: 应用了自定义 patch</li></ul><h2 id="架构设计" tabindex="-1">架构设计 <a class="header-anchor" href="#架构设计" aria-label="Permalink to &quot;架构设计&quot;">​</a></h2><h3 id="mcp-oauth-集成" tabindex="-1">MCP OAuth 集成 <a class="header-anchor" href="#mcp-oauth-集成" aria-label="Permalink to &quot;MCP OAuth 集成&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OAuth 回调端点: https://www.cursor.com/agents/mcp/oauth/callback</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>MCP 服务器可以通过 OAuth 进行身份认证。</p><h3 id="mcp-服务器列表" tabindex="-1">MCP 服务器列表 <a class="header-anchor" href="#mcp-服务器列表" aria-label="Permalink to &quot;MCP 服务器列表&quot;">​</a></h3><p>信任的第三方 MCP 服务器（从 product.json 的 linkProtectionTrustedDomains 提取）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mcp.notion.com         — Notion 知识库</span></span>
<span class="line"><span>mcp.sentry.dev         — Sentry 错误追踪</span></span>
<span class="line"><span>mcp.atlassian.com      — Atlassian 全家桶</span></span>
<span class="line"><span>mcp.intercom.com       — Intercom 客服</span></span>
<span class="line"><span>mcp.asana.com          — Asana 项目管理</span></span>
<span class="line"><span>mcp.linear.app         — Linear 项目管理</span></span>
<span class="line"><span>mcp.figma.com          — Figma 设计工具</span></span>
<span class="line"><span>mcp.context7.com       — Context7 上下文</span></span>
<span class="line"><span>mcp.prisma.io          — Prisma 数据库</span></span>
<span class="line"><span>mcp.squareup.com       — Square 支付</span></span>
<span class="line"><span>playwright.dev         — Playwright 浏览器测试</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="核心发现" tabindex="-1">核心发现 <a class="header-anchor" href="#核心发现" aria-label="Permalink to &quot;核心发现&quot;">​</a></h2><h3 id="_1-品牌资源" tabindex="-1">1. 品牌资源 <a class="header-anchor" href="#_1-品牌资源" aria-label="Permalink to &quot;1. 品牌资源&quot;">​</a></h3><p>MCP 使用的品牌标志：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://ptht05hbb1ssoooe.public.blob.vercel-storage.com/assets/uploads/cursorlogomcpv3.svg</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>存储在 Vercel Blob Storage 上的 Cursor MCP Logo。</p><h3 id="_2-cursor-vm-基础设施-与-agent-共享" tabindex="-1">2. Cursor VM 基础设施 (与 Agent 共享) <a class="header-anchor" href="#_2-cursor-vm-基础设施-与-agent-共享" aria-label="Permalink to &quot;2. Cursor VM 基础设施 (与 Agent 共享)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://dev.cursorvm-manager.com</span></span>
<span class="line"><span>https://us1.cursorvm-manager.com  (及更多区域)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>MCP 扩展同样引用 Cursor VM 管理基础设施。</p><h3 id="_3-扩展钩子" tabindex="-1">3. 扩展钩子 <a class="header-anchor" href="#_3-扩展钩子" aria-label="Permalink to &quot;3. 扩展钩子&quot;">​</a></h3><ul><li>启动完成时激活 (<code>onStartupFinished</code>)</li><li>URI 协议处理 (<code>onUri</code>)，用于处理 MCP OAuth 回调</li></ul><h2 id="mcp-集成点" tabindex="-1">MCP 集成点 <a class="header-anchor" href="#mcp-集成点" aria-label="Permalink to &quot;MCP 集成点&quot;">​</a></h2><p>MCP 在 Cursor 中服务于以下场景：</p><ol><li><strong>Agent 工具扩展</strong> — Agent 可以通过 MCP 调用外部服务</li><li><strong>第三方集成</strong> — 信任的第三方 MCP 服务器</li><li><strong>OAuth 认证</strong> — MCP 服务器的认证流程</li><li><strong>工具发现</strong> — 发现可用工具和资源</li></ol><h2 id="cursor-对-mcp-sdk-的定制-patch-分析" tabindex="-1">Cursor 对 MCP SDK 的定制 (Patch 分析) <a class="header-anchor" href="#cursor-对-mcp-sdk-的定制-patch-分析" aria-label="Permalink to &quot;Cursor 对 MCP SDK 的定制 (Patch 分析)&quot;">​</a></h2><p>Cursor 对 @modelcontextprotocol/sdk v1.25.1 应用了自定义 patch，文件位于：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>extensions/cursor-agent-exec/patches/@modelcontextprotocol+sdk+1.25.1.patch</span></span>
<span class="line"><span>extensions/cursor-mcp/patches/@modelcontextprotocol+sdk+1.25.1.patch</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这表明 Cursor 对标准 MCP 协议进行了扩展修改。</p><h2 id="安全考虑" tabindex="-1">安全考虑 <a class="header-anchor" href="#安全考虑" aria-label="Permalink to &quot;安全考虑&quot;">​</a></h2><ul><li>MCP 服务器通过链接保护白名单控制</li><li>OAuth 认证流程保护敏感操作</li><li>扩展在 workspace 级别运行（可访问工作区资源）</li><li>信任的第三方 MCP 服务器经过审核</li></ul>`,33)])])}const m=s(r,[["render",o]]);export{u as __pageData,m as default};
